// Parse Typeform webhook payload
const webhookData = $input.first().json;
const formResponse = webhookData.form_response || webhookData;

// Extract answers from Typeform response
const answers = {};
if (formResponse.answers) {
  formResponse.answers.forEach(answer => {
    const fieldRef = answer.field?.ref || answer.field?.id || '';
    if (answer.type === 'email') answers.email = answer.email || '';
    else if (answer.type === 'text') answers[fieldRef] = answer.text || '';
    else if (answer.type === 'choice') answers[fieldRef] = answer.choice?.label || answer.choice?.other || '';
    else if (answer.type === 'choices') answers[fieldRef] = answer.choices?.labels || [];
    else if (answer.type === 'number') answers[fieldRef] = answer.number || 0;
    else if (answer.type === 'phone_number') answers[fieldRef] = answer.phone_number || '';
  });
}

// Map to our fields
const leadData = {
  email: answers.email || answers.Email || '',
  industry: answers.industry || answers.Industry || '',
  time_waster: answers.time_waster || answers['time-waster'] || '',
  team_size: parseInt(answers.team_size || answers['team-size'] || 0),
  current_tools: Array.isArray(answers.current_tools || answers['current-tools']) ? answers.current_tools || answers['current-tools'] : [],
  timeline: answers.timeline || answers.Timeline || '',
  phone: answers.phone || answers.Phone || '',
  form_id: webhookData.form_id || '',
  submitted_at: formResponse.submitted_at || new Date().toISOString(),
  token: formResponse.token || ''
};

return [{
  json: {
    success: true,
    leadData: leadData,
    raw: webhookData
  }
}];

